import type { SVGProps } from "react";

/**
 * Gally Capital Protocol — brand marks.
 *
 * The artwork is the master logo itself, vectorised from the source raster so
 * there is no baked-in white plate: it sits on any background and recolours
 * with the theme. Ink (the "GALLY" wordmark + "CAPITAL PROTOCOL" line) paints
 * with `currentColor`; the signature forest-green accent — the triangle nested
 * in the "A" and the two flanking rules — is fixed brand green.
 *
 * Do not hand-edit the path data. It is a `potrace` vectorisation of the logo;
 * regenerate from the source art if the logo changes.
 */

type SvgP = SVGProps<SVGSVGElement> & { className?: string; title?: string };

/** Logo accent green (the triangle + rules). Matches the master art. */
const BRAND_GREEN = "#5E7E2A";

