// The isolated "G" glyph lives in its own 262x247 box.
const G_TF = "translate(0,247) scale(0.01,-0.01)";
const G_D =
  "M11567 24143 c-5070 -788 -9360 -4421 -10706 -9064 -983 -3392 -201 -7077 2123 -10000 2611 -3285 7021 -5070 11559 -4680 5150 444 9036 3367 10603 7976 481 1415 670 2702 634 4325 l-30 1350 -6175 26 -6175 26 0 -2076 0 -2076 2925 33 c1609 18 3247 3 3641 -33 l716 -65 -77 -268 c-150 -523 -702 -1500 -1193 -2111 -1986 -2475 -5509 -3422 -8736 -2348 -1676 558 -3288 1995 -4114 3667 -630 1275 -801 2044 -798 3575 2 1129 33 1342 317 2200 433 1310 922 2103 1918 3110 717 725 1001 934 1801 1323 1282 624 2249 810 3843 739 2235 -101 4105 -902 5507 -2359 220 -229 448 -404 507 -390 241 61 3935 2536 3939 2640 7 189 -1909 1957 -2675 2468 -2623 1751 -6152 2510 -9354 2012z";

/**
 * Full lock-up: "GALLY" + "CAPITAL PROTOCOL" with the green triangle + rules.
 * Width-driven — set a width and the height follows the 1202:338 ratio.
 */
export function GallyWordmark({ className, title = "Gally Capital Protocol", ...rest }: SvgP) {
  return (
    <svg
      viewBox="0 0 1202 338"
      className={className}
      role="img"
      aria-label={title}
      fill="none"
      {...rest}
    >
      <g transform={WORDMARK_TF}>
        <path d={WORDMARK_INK_D} fill="currentColor" />
        <path d={WORDMARK_GREEN_D} fill={BRAND_GREEN} />
      </g>
    </svg>
  );
}

/**
 * Compact square app-mark: the exact "G" on an ink tile with the green triangle
 * nested in its mouth — the same letter+triangle motif as the wordmark, sized
 * to read down to a favicon. Self-coloured (not theme-dependent) so it stays
 * on-brand on any surface. Used for the favicon / app icons.
 */
export function GallyMark({ className, title = "Gally", ...rest }: SvgP) {
  return (
    <svg
      viewBox="0 0 100 100"
      className={className}
      role="img"
      aria-label={title}
      {...rest}
    >
      <rect width="100" height="100" rx="23" fill="#1C2226" />
      <g transform="translate(21.84,23.45) scale(0.215)">
        <g transform={G_TF}>
          <path d={G_D} fill="#F4F5F1" />
        </g>
      </g>
      <polygon points="57,45.5 71,45.5 64,58.5" fill={BRAND_GREEN} />
    </svg>
  );
}

/**
 * Minimal "G" glyph in `currentColor`, no tile — for tight inline spots that
 * should inherit the surrounding text colour.
 */
export function GallyGlyph({ className, title = "Gally", ...rest }: SvgP) {
  return (
    <svg
      viewBox="0 0 262 247"
      className={className}
      role="img"
      aria-label={title}
      {...rest}
    >
      <g transform={G_TF}>
        <path d={G_D} fill="currentColor" />
      </g>
    </svg>
  );
}
